const body = items[0].json.body || items[0].json;

// Validate phone number
let phone = (body.phone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '254' + phone.substring(1);
if (!phone.startsWith('254')) phone = '254' + phone;

const amount = parseInt(body.amount) || 0;
if (amount < 1) {
  return [{ json: { error: 'Invalid amount', status: 'failed' } }];
}
if (phone.length !== 12) {
  return [{ json: { error: 'Invalid phone number', status: 'failed' } }];
}

return [{
  json: {
    phone: phone,
    amount: amount,
    service: body.service || 'unknown',
    account_ref: body.account_ref || 'AEGO-' + Date.now(),
    timestamp: new Date().toISOString()
  }
}];

const mpesaResponse = items[0].json;
const requestData = $('Validate Payment').first().json;

const checkoutId = mpesaResponse.CheckoutRequestID || mpesaResponse.checkoutRequestId || '';
const responseCode = mpesaResponse.ResponseCode || mpesaResponse.responseCode || '';

if (responseCode !== '0' && responseCode !== 0) {
  return [{ json: { error: mpesaResponse.errorMessage || mpesaResponse.ResponseDescription || 'STK push failed', status: 'failed' } }];
}

// Save pending payment to DB
return [{
  json: {
    checkoutRequestId: checkoutId,
    phone: requestData.phone,
    amount: requestData.amount,
    service: requestData.service,
    account_ref: requestData.account_ref,
    status: 'pending',
    created_at: new Date().toISOString()
  }
}];

const callback = items[0].json.body || items[0].json;
const stkCallback = callback.Body?.stkCallback || callback.StkCallback || callback;

const resultCode = stkCallback.ResultCode || stkCallback.resultCode;
const resultDesc = stkCallback.ResultDesc || stkCallback.resultDesc || '';
const checkoutId = stkCallback.CheckoutRequestID || stkCallback.checkoutRequestId || '';

let mpesaReceipt = '';
let amount = 0;
let phone = '';

if (resultCode === 0 || resultCode === '0') {
  // Payment successful
  const metadata = stkCallback.CallbackMetadata?.Item || stkCallback.callbackMetadata?.item || [];
  for (const item of metadata) {
    if (item.Name === 'MpesaReceiptNumber' || item.name === 'MpesaReceiptNumber') mpesaReceipt = item.Value || item.value;
    if (item.Name === 'Amount' || item.name === 'Amount') amount = item.Value || item.value;
    if (item.Name === 'PhoneNumber' || item.name === 'PhoneNumber') phone = item.Value || item.value;
  }
}

return [{
  json: {
    checkoutRequestId: checkoutId,
    result_code: resultCode,
    result_desc: resultDesc,
    mpesa_receipt: mpesaReceipt,
    amount: amount,
    phone: phone,
    status: (resultCode === 0 || resultCode === '0') ? 'success' : 'failed',
    timestamp: new Date().toISOString()
  }
}];

const payment = items[0].json;

return [{
  json: {
    type: 'payment_confirmed',
    checkoutRequestId: payment.checkoutRequestId,
    mpesa_receipt: payment.mpesa_receipt,
    amount: payment.amount,
    phone: payment.phone,
    message: `Payment of KES ${payment.amount} confirmed. M-Pesa ref: ${payment.mpesa_receipt}`,
    timestamp: payment.timestamp
  }
}];
